const r='.hero{position:relative;overflow:hidden;border-radius:24px;border:1px solid var(--border);background:radial-gradient(130% 130% at 110% -12%,rgba(255,47,109,.28),transparent 52%),radial-gradient(110% 110% at -8% 120%,rgba(125,85,255,.28),transparent 56%),linear-gradient(180deg,#161c2bf2,#0f1521f2);box-shadow:var(--shadow-lg);padding:1.5rem;animation:hero-in .46s ease both}.hero:after{content:"";position:absolute;inset:auto -16% -44% auto;width:280px;height:280px;border-radius:999px;background:radial-gradient(circle,rgba(49,196,255,.34),transparent 70%);pointer-events:none}.hero-title{margin:0;font-size:clamp(1.45rem,3vw,1.95rem);line-height:1.15;letter-spacing:-.02em;font-weight:700;color:var(--text-1)}.hero-subtitle{margin:.72rem 0 0;max-width:44rem;font-size:.95rem;color:var(--text-2);line-height:1.5}.hero-actions{display:flex;flex-wrap:wrap;gap:.72rem;margin-top:1.3rem}.hero-link{text-decoration:none;display:inline-flex;align-items:center;border-radius:11px;padding:.62rem .98rem;font-size:.87rem;font-weight:700;border:1px solid transparent;transition:transform .16s ease,background-color .16s ease,border-color .16s ease}.hero-link:hover{transform:translateY(-1px)}.hero-link-primary{color:#fff;background:linear-gradient(118deg,var(--accent-1),var(--accent-2) 50%,var(--accent-3));box-shadow:0 10px 22px -14px #ff2f6de6}.hero-link-primary:hover{filter:brightness(1.05)}.hero-link-secondary{background:#ffffff08;color:var(--text-2);border-color:var(--border)}.hero-link-secondary:hover{color:var(--text-1);background:#ffffff14}@keyframes hero-in{0%{transform:translateY(12px);opacity:0}to{transform:translateY(0);opacity:1}}';export{r as s};
